import{_ as l,o as t,c as i,a2 as e}from"./chunks/framework.BZO4qERu.js";const b=JSON.parse('{"title":"騎砍2 | 家族與結婚系統：傳宗接代也是戰略","description":"","frontmatter":{},"headers":[],"relativePath":"bannerlord/clan-family.md","filePath":"bannerlord/clan-family.md"}'),r={name:"bannerlord/clan-family.md"};function o(h,a,d,n,s,u){return t(),i("div",null,[...a[0]||(a[0]=[e('<h1 id="騎砍2-家族與結婚系統-傳宗接代也是戰略" tabindex="-1">騎砍2 | 家族與結婚系統：傳宗接代也是戰略 <a class="header-anchor" href="#騎砍2-家族與結婚系統-傳宗接代也是戰略" aria-label="Permalink to &quot;騎砍2 | 家族與結婚系統：傳宗接代也是戰略&quot;">​</a></h1><hr><h2 id="前言" tabindex="-1">前言 <a class="header-anchor" href="#前言" aria-label="Permalink to &quot;前言&quot;">​</a></h2><p>騎砍2不是永遠只有你這一代。你的人物會老、會死——但你的家族可以延續。結婚不只是浪漫，更是政治聯姻、獲得強力夥伴、延續血脈的手段。</p><hr><h2 id="一、家族系統基礎" tabindex="-1">一、家族系統基礎 <a class="header-anchor" href="#一、家族系統基礎" aria-label="Permalink to &quot;一、家族系統基礎&quot;">​</a></h2><h3 id="_1-1-家族等級" tabindex="-1">1.1 家族等級 <a class="header-anchor" href="#_1-1-家族等級" aria-label="Permalink to &quot;1.1 家族等級&quot;">​</a></h3><ul><li>家族等級由<strong>聲望</strong>決定</li><li>等級越高 → 可帶兵越多 → 可招募更多夥伴 → 可組建更多部隊</li><li>家族等級 1 → 可帶 1 個夥伴部隊</li><li>家族等級 3 → 可建立王國（基本門檻）</li></ul><h3 id="_1-2-家族成員" tabindex="-1">1.2 家族成員 <a class="header-anchor" href="#_1-2-家族成員" aria-label="Permalink to &quot;1.2 家族成員&quot;">​</a></h3><table tabindex="0"><thead><tr><th>成員</th><th>來源</th><th>用途</th></tr></thead><tbody><tr><td>你自己</td><td>—</td><td>主角</td></tr><tr><td>兄弟/姊妹</td><td>遊戲開場（部分出身有）</td><td>初期免費夥伴</td></tr><tr><td>配偶</td><td>結婚</td><td>強力夥伴 + 生育</td></tr><tr><td>子女</td><td>生育</td><td>接班人/未來夥伴</td></tr><tr><td>兄弟/姊妹的配偶</td><td>安排婚姻</td><td>擴大家族</td></tr></tbody></table><hr><h2 id="二、結婚系統" tabindex="-1">二、結婚系統 <a class="header-anchor" href="#二、結婚系統" aria-label="Permalink to &quot;二、結婚系統&quot;">​</a></h2><h3 id="_2-1-為什麼要結婚" tabindex="-1">2.1 為什麼要結婚 <a class="header-anchor" href="#_2-1-為什麼要結婚" aria-label="Permalink to &quot;2.1 為什麼要結婚&quot;">​</a></h3><ul><li>配偶是<strong>永久免費夥伴</strong>，通常屬性不錯</li><li>可以獲得配偶家族的關係加成</li><li>可以生育子女延續血脈</li><li>配偶的裝備通常不錯（直接拿走用）</li></ul><h3 id="_2-2-怎麼找對象" tabindex="-1">2.2 怎麼找對象 <a class="header-anchor" href="#_2-2-怎麼找對象" aria-label="Permalink to &quot;2.2 怎麼找對象&quot;">​</a></h3><p>打開百科全書（N鍵）→ 英雄 → 篩選「女性/男性」→ 找「未婚」的貴族。</p><p>重點看：</p><ul><li><strong>年齡</strong>：年輕的可以多生幾年</li><li><strong>技能</strong>：戰鬥型？管理型？看你缺什麼</li><li><strong>家族</strong>：大領主的女兒代表政治聯姻價值高</li></ul><h3 id="_2-3-怎麼求婚" tabindex="-1">2.3 怎麼求婚 <a class="header-anchor" href="#_2-3-怎麼求婚" aria-label="Permalink to &quot;2.3 怎麼求婚&quot;">​</a></h3><ol><li>先跟對方聊天 → 選擇浪漫選項（需要魅力值）</li><li>玩幾次說服小遊戲</li><li>成功後需要跟對方的家族族長談判（通常是付錢）</li><li>費用：幾千到十幾萬金不等，大領主的女兒最貴</li></ol><blockquote><p>💡 魅力值越高越容易成功。多參加競技場和宴會可以提升魅力。</p></blockquote><hr><h2 id="三、生育系統" tabindex="-1">三、生育系統 <a class="header-anchor" href="#三、生育系統" aria-label="Permalink to &quot;三、生育系統&quot;">​</a></h2><h3 id="_3-1-如何生育" tabindex="-1">3.1 如何生育 <a class="header-anchor" href="#_3-1-如何生育" aria-label="Permalink to &quot;3.1 如何生育&quot;">​</a></h3><ul><li>配偶留在同一個城鎮/城堡，你在外面跑</li><li>等待一段時間（遊戲內數週到數月）</li><li>系統會通知你「你的妻子懷孕了」→ 再等一段時間 → 孩子出生</li></ul><blockquote><p>配偶需要在定居點「休息」才會懷孕。一直帶在部隊裡打仗是不會生的。</p></blockquote><h3 id="_3-2-孩子的用途" tabindex="-1">3.2 孩子的用途 <a class="header-anchor" href="#_3-2-孩子的用途" aria-label="Permalink to &quot;3.2 孩子的用途&quot;">​</a></h3><ul><li>繼承人：你的人物死後由孩子接手</li><li>免費夥伴：孩子成年後技能不錯</li><li>政治聯姻：安排孩子跟其他貴族結婚 → 結盟</li></ul><h3 id="_3-3-孩子養成" tabindex="-1">3.3 孩子養成 <a class="header-anchor" href="#_3-3-孩子養成" aria-label="Permalink to &quot;3.3 孩子養成&quot;">​</a></h3><ul><li>孩子 18 歲成年</li><li>童年期可以選擇教育方向（影響成年技能）</li><li>成年後可以當夥伴、帶部隊、甚至當領主</li></ul><hr><h2 id="四、家族政治" tabindex="-1">四、家族政治 <a class="header-anchor" href="#四、家族政治" aria-label="Permalink to &quot;四、家族政治&quot;">​</a></h2><h3 id="_4-1-安排婚姻" tabindex="-1">4.1 安排婚姻 <a class="header-anchor" href="#_4-1-安排婚姻" aria-label="Permalink to &quot;4.1 安排婚姻&quot;">​</a></h3><p>不只你可以結婚——你的兄弟/姊妹/孩子也可以。</p><p>安排家族成員跟其他貴族結婚 → 獲得那個家族的關係加成 → 挖角時更容易。</p><h3 id="_4-2-家族部隊" tabindex="-1">4.2 家族部隊 <a class="header-anchor" href="#_4-2-家族部隊" aria-label="Permalink to &quot;4.2 家族部隊&quot;">​</a></h3><p>家族等級 2 以上，可以讓夥伴或家族成員帶自己的部隊。</p><ul><li>優點：多一支部隊在地圖上幫你打仗</li><li>缺點：他們自己也會花錢和食物</li><li>部隊會自動加入你所在的軍團</li></ul><hr><h2 id="五、接班規劃" tabindex="-1">五、接班規劃 <a class="header-anchor" href="#五、接班規劃" aria-label="Permalink to &quot;五、接班規劃&quot;">​</a></h2><p>你的人物會老。年齡到了屬性會下降，最終可能老死。</p><h3 id="接班準備" tabindex="-1">接班準備 <a class="header-anchor" href="#接班準備" aria-label="Permalink to &quot;接班準備&quot;">​</a></h3><ol><li>確保有至少一個成年孩子</li><li>孩子成年後帶在身邊練技能</li><li>你的人物死後 → 自動切換到繼承人</li><li>繼承人保留家族資產和關係</li></ol><hr><h2 id="📖-相關攻略" tabindex="-1">📖 相關攻略 <a class="header-anchor" href="#📖-相關攻略" aria-label="Permalink to &quot;📖 相關攻略&quot;">​</a></h2><ul><li><a href="./companions.html">騎砍2 | 夥伴全指南</a></li><li><a href="./kingdom-building.html">騎砍2 | 自立為王</a></li><li><a href="./kingdom-management.html">騎砍2 | 王國管理深度指南</a></li></ul><hr><p><em>Blades Game 游刃攻略 — 遊刃有餘的遊戲攻略。全部原創內容，未經授權禁止轉載。</em></p><hr><h2 id="更新紀錄" tabindex="-1">更新紀錄 <a class="header-anchor" href="#更新紀錄" aria-label="Permalink to &quot;更新紀錄&quot;">​</a></h2><ul><li><strong>2026-06-11</strong>：文章建立。依據遊戲 v1.4.x 正式版撰寫。</li></ul>',51)])])}const m=l(r,[["render",o]]);export{b as __pageData,m as default};
